#include <bits/stdc++.h>
using namespace std;

long long sum=0,cnt=0,ans=0;
long long n,m,w,a[200005],t=0;

int main()
{
	scanf ("%lld%lld%lld",&n,&m,&w);
	for(int i=1;i<=n;i++)
	{
		scanf ("%lld",&a[i]);
	}
	sort(a+1,a+n+1);
	for(int i=n;i>=1;i--) 
	{
		sum+=a[i]; 
		t++;
		if(t==m) 
		{
			ans+=min(sum,w); 
			sum=0;
			t=0;
		}
	}
	ans=ans+min(sum,w); 
	printf("%lld",ans);
	return 0;
}
